235	//===----------------------------------------------------------------------===//
236	// String Section Management
237	//===----------------------------------------------------------------------===//
238	// string-section =:
239	//   numStrings[varint]
240	//   padding[bytes]            // Align to 4 bytes
241	//   stringOffsets[uint32_t]   // Array of offsets, one per string
242	//   stringData[bytes]         // Concatenated string data
243	//
244	namespace {
245	struct StringManager {
246	  uint64_t getStringIndex(StringRef str) {
247	    auto it = stringIndexMap.find(str);
248	    if (it != stringIndexMap.end())
249	      return it->second;
250	    uint64_t index = stringIndexMap.size();
251	    stringIndexMap[str] = index;
252	    return index;
253	  }
254	
255	  LogicalResult writeStringSection(raw_ostream &stream) {
256	    SmallVector<char> buffer;
257	    llvm::raw_svector_ostream sectionStream(buffer);
258	    EncodingWriter sectionWriter(sectionStream);
259	    sectionWriter.writeVarInt(stringIndexMap.size());
260	    // Align the string section
261	    uint64_t alignmentNeeded = alignof(uint32_t);
262	    sectionWriter.alignTo(alignmentNeeded);
263	
264	    // Save the current position to fix up offsets later.
265	    auto offsetsPtr = sectionWriter.tell();
266	
267	    // Reserve space for the offset table (filled later).
268	    for (size_t i = 0; i < stringIndexMap.size(); ++i)
269	      sectionWriter.writeLE<uint32_t>(0);
270	
271	    // Write each string and record its starting offset.
272	    SmallVector<uint32_t> finalOffsets;
273	    finalOffsets.reserve(stringIndexMap.size());
274	
275	    uint32_t running = 0;
276	    for (const auto &str : stringIndexMap) {
277	      finalOffsets.push_back(running);
278	      sectionWriter.write(str.first);
279	      running += str.first.size();
280	    }
281	
282	    // Copy the pre-computed offsets into the reserved slot.
283	    std::copy_n(finalOffsets.begin(), finalOffsets.size(),
284	                reinterpret_cast<uint32_t *>(buffer.data() + offsetsPtr));
285	
286	    writeSectionHeader(stream, Bytecode::Section::String, buffer.size(),
287	                       sectionWriter.getRequiredAlignment());
288	    stream.write(buffer.data(), buffer.size());
289	    return success();
290	  }
291	
292	private:
293	  llvm::MapVector<StringRef, uint64_t> stringIndexMap;
294	};
295	} // end anonymous namespace
296	
297	//===----------------------------------------------------------------------===//
298	// Type Section Management
299	// Collects and writes all unique types used in the module.
300	//===----------------------------------------------------------------------===//
301	// type-section =:
302	//   numTypes[varint]
303	//   padding[bytes]          // Align to 4 bytes
304	//   typeOffsets[uint32_t]   // Array of offsets, one per type
305	//   typeData[bytes]         // Concatenated type data
306	//
307	// type-data =:
308	//   typeTag[byte]           // Indicates the kind of type
309	//   type-specific-data      // Format depends on typeTag
310	//
311	// integer-type =: typeTag[I1/I32/I64]  // No additional data
312	// float-type =: typeTag[F32]           // No additional data
313	//
314	// tile-type =:
315	//   typeTag[Tile]
316	//   elementTypeIndex[varint]
317	//   rank[varint]
318	//   dimensions[int64_t*rank]
319	//
320	// function-type =:
321	//   typeTag[Func]
322	//   numInputs[varint]
323	//   inputTypeIndices[varint*numInputs]
324	//   numResults[varint]
325	//   resultTypeIndices[varint*numResults]
326	//
327	namespace {
328	struct TypeManager {
329	public:
330	  TypeManager(const BytecodeWriterConfig &config) : config(config) {}
331	
332	  // Gets or creates an index for a type in the type table.
333	  uint64_t getTypeIndex(Type type) {
334	    // Use the type's memory address as a unique key for lookup
335	    const void *key = type.getAsOpaquePointer();
336	    auto it = typeIndexMap.find(key);
337	    if (it != typeIndexMap.end())
338	      return it->second;
339	    // Ensure dependent/nested types are registered before the type itself
340	    registerDependentTypes(type);
341	    uint64_t index = typeList.size();
342	    typeIndexMap[key] = index;
343	    typeList.push_back(type);
344	    return index;
345	  }
346	
347	  LogicalResult writeTypeSection(raw_ostream &stream) {
348	    SmallVector<char> buffer;
349	    llvm::raw_svector_ostream sectionStream(buffer);
350	    EncodingWriter sectionWriter(sectionStream);
351	
352	    sectionWriter.writeVarInt(typeList.size());
353	    // Align the type section
354	    uint64_t alignmentNeeded = alignof(uint32_t);
355	    sectionWriter.alignTo(alignmentNeeded);
356	
357	    // Save the current position to fix up offsets later.
358	    auto offsetsPtr = sectionWriter.tell();
359	
360	    // Reserve space for the offset table (filled later).
361	    for (size_t i = 0; i < typeList.size(); ++i)
362	      sectionWriter.writeLE<uint32_t>(0);
363	
364	    // Write each type and record its starting offset.
365	    SmallVector<uint32_t> finalOffsets;
366	    finalOffsets.reserve(typeList.size());
367	
368	    uint32_t running = 0;
369	    for (Type type : typeList) {
370	      finalOffsets.push_back(running);
371	      auto before = sectionWriter.tell();
372	      if (failed(serializeType(type, sectionWriter)))
373	        return failure();
374	      running += static_cast<uint32_t>(sectionWriter.tell() - before);
375	    }
376	
377	    // Copy the pre-computed offsets into the reserved slot.
378	    std::copy_n(finalOffsets.begin(), finalOffsets.size(),
379	                reinterpret_cast<uint32_t *>(buffer.data() + offsetsPtr));
380	
381	    writeSectionHeader(stream, Bytecode::Section::Type, buffer.size(),
382	                       sectionWriter.getRequiredAlignment());
383	    stream.write(buffer.data(), buffer.size());
384	    return success();
385	  }
386	
387	  /// Helper function to write the index of a given type to the writer.
388	  LogicalResult writeTypeIndex(Type type, EncodingWriter &writer) {
389	    // Ensure type is registered and get its index.
390	    uint64_t index = getTypeIndex(type);
391	    writer.writeVarInt(index);
392	    return success();
393	  }
394	
395	private:
396	  // Include generated type serialization functions.
397	#define GEN_TYPE_WRITERS
398	#include "TypeBytecode.inc"
399	
400	  LogicalResult serializeType(Type type, EncodingWriter &writer){
401	  // Generated type serialization dispatch.
402	#define GEN_TYPE_WRITER_DISPATCH
403	#include "TypeBytecode.inc"
404	  }
405	
406	  LogicalResult
407	      serializeFunctionType(FunctionType type, EncodingWriter &writer) {
408	    // Write the function type with tag
409	    writer.writeVarInt(Bytecode::TypeTag::FunctionType);
410	    // Using VarInt for numParams per spec
411	    uint64_t numInputs = type.getNumInputs();
412	    writer.writeVarInt(numInputs);
413	    // Serialize input types
414	    for (Type input : type.getInputs())
415	      if (failed(writeTypeIndex(input, writer)))
416	        return failure();
417	    // Using VarInt for numResults per spec
418	    uint64_t numResults = type.getNumResults();
419	    writer.writeVarInt(numResults);
420	    // Serialize result types
421	    for (Type result : type.getResults())
422	      if (failed(writeTypeIndex(result, writer)))
423	        return failure();
424	    return success();
425	  }
426	
427	  // Helper to recursively register dependent types before the main type.
428	  void registerDependentTypes(Type type) {
429	    // Check if the type itself is already registered or being registered
430	    if (typeIndexMap.count(type.getAsOpaquePointer()))
431	      return;
432	
433	      // Auto-generated dependent type registration for CudaTile types.
434	#define GEN_DEPENDENT_TYPE_REGISTRATION
435	#include "TypeBytecode.inc"
436	
437	    // FunctionType is not a CudaTile type, handle it manually.
438	    if (auto funcType = dyn_cast<FunctionType>(type)) {
439	      for (Type input : funcType.getInputs())
440	        getTypeIndex(input);
441	      for (Type result : funcType.getResults())
442	        getTypeIndex(result);
443	    }
444	  }
445	
446	  llvm::MapVector<const void *, uint64_t> typeIndexMap;
447	  SmallVector<Type> typeList;
448	  const BytecodeWriterConfig &config;
449	};
450	} // end anonymous namespace
451	
452	//===----------------------------------------------------------------------===//
453	// Constant Section Management
454	//===----------------------------------------------------------------------===//
455	// constant-section =:
456	//   numConstants[varint]
457	//   padding[bytes]             // Align to 8 bytes
458	//   constantOffsets[uint64_t]  // Array of offsets, one per constant
459	//   constantData[bytes]        // Concatenated constant data
460	//
461	// constant-data format depends on the attribute type
462	// scalar-constant =: raw binary representation of the scalar value
463	//
464	namespace {
465	struct ConstantManager {
466	  LogicalResult addConstant(Attribute attr, uint64_t &index) {
467	    auto it = constantsMap.find(attr);
468	    if (it != constantsMap.end()) {
469	      index = std::distance(constantsMap.begin(), it);
470	      return success();
471	    }
472	    SmallVector<char> data;
473	    llvm::raw_svector_ostream dataStream(data);
474	    EncodingWriter writer(dataStream);
475	    if (failed(serializeAttribute(attr, writer)))
476	      return emitError(UnknownLoc::get(attr.getContext()),
477	                       "failed to serialize attribute");
478	    index = constantsMap.size();
479	    constantsMap[attr] = std::move(data);
480	    return success();
481	  }
482	
483	  // Look up a constant by attribute without adding it
484	  LogicalResult getConstantIndex(Attribute attr, uint64_t &index) const {
485	    auto it = constantsMap.find(attr);
486	    if (it != constantsMap.end()) {
487	      index = std::distance(constantsMap.begin(), it);
488	      return success();
489	    }
490	    return failure();
491	  }
492	
493	  // Provide access to the constant map
494	  const llvm::MapVector<Attribute, SmallVector<char>> &getConstantsMap() const {
495	    return constantsMap;
496	  }
497	
498	  /// Serializes a single MLIR attribute into its raw byte representation.
499	  /// This function handles different attribute types, focusing on scalar
500	  /// and dense element attributes suitable for the constant pool.
501	  LogicalResult serializeAttribute(Attribute attr, EncodingWriter &writer) {
502	    if (auto denseAttr = dyn_cast<DenseElementsAttr>(attr)) {
503	      // Get the raw data buffer in little-endian format.
504	      ArrayRef<char> rawData = denseAttr.getRawData();
505	      // Write the size of the raw buffer.
506	      writer.writeVarInt(rawData.size());
507	      // Write the raw buffer content.
508	      writer.write(rawData.data(), rawData.size());
509	      return success();
510	    } else if (auto intAttr = dyn_cast<IntegerAttr>(attr)) {
511	      APInt value = intAttr.getValue();
512	      writer.writeLE<uint64_t>(value.getZExtValue());
513	      return success();
514	    } else if (auto boolAttr = dyn_cast<BoolAttr>(attr)) {
515	      uint8_t boolValue = boolAttr.getValue() ? 0x01 : 0x00;
516	      writer.writeByte(boolValue);
517	      return success();
518	    } else if (auto floatAttr = dyn_cast<FloatAttr>(attr)) {
519	      writeAPFloatRepresentation(floatAttr.getValue(), writer);
520	      return success();
521	    }
522	    return emitError(UnknownLoc::get(attr.getContext()),
523	                     "unsupported attribute type in constant data");
524	  }
525	
526	  LogicalResult writeConstantSection(raw_ostream &stream) {
527	    // If there are no constants, skip writing this section entirely
528	    if (constantsMap.empty())
529	      return success();
530	    SmallVector<char> buffer;
531	    llvm::raw_svector_ostream sectionStream(buffer);
532	    EncodingWriter sectionWriter(sectionStream);
533	    // Write numConstants
534	    sectionWriter.writeVarInt(constantsMap.size());
535	    // Align the constant section
536	    uint64_t alignmentNeeded = alignof(uint64_t);
537	    sectionWriter.alignTo(alignmentNeeded);
538	
539	    // Save the current position to fix up offsets later.
540	    auto offsetsPtr = sectionWriter.tell();
541	
542	    // Reserve space for the offset table (filled later).
543	    for (size_t i = 0; i < constantsMap.size(); ++i)
544	      sectionWriter.writeLE<uint64_t>(0);
545	
546	    // Write each constant and record its starting offset.
547	    SmallVector<uint64_t> finalOffsets;
548	    finalOffsets.reserve(constantsMap.size());
549	
550	    uint64_t running = 0;
551	    for (const auto &pair : constantsMap) {
552	      if (pair.second.empty())
553	        return emitError(UnknownLoc::get(pair.first.getContext()))
554	               << "constant has empty serialized representation, which is "
555	                  "invalid";
556	      finalOffsets.push_back(running);
557	      sectionWriter.write(pair.second.data(), pair.second.size());
558	      running += pair.second.size();
559	    }
560	
561	    // Copy the pre-computed offsets into the reserved slot.
562	    std::copy_n(finalOffsets.begin(), finalOffsets.size(),
563	                reinterpret_cast<uint64_t *>(buffer.data() + offsetsPtr));
564	
565	    writeSectionHeader(stream, Bytecode::Section::Constant, buffer.size(),
566	                       sectionWriter.getRequiredAlignment());
567	    // Write the section content
568	    stream.write(buffer.data(), buffer.size());
569	    return success();
570	  }
571	
572	private:
573	  llvm::MapVector<Attribute, SmallVector<char>> constantsMap;
574	};
