576	//===----------------------------------------------------------------------===//
577	// DebugInfo Section
578	//===----------------------------------------------------------------------===//
579	
580	/// This class manages writing debug info attributes to bytecode format.
581	class DebugInfoWriter {
582	public:
583	  DebugInfoWriter(StringManager &strMgr) : strMgr(strMgr) {}
584	
585	  /// This method gets or creates an index for an operation.
586	  uint64_t getOpIndex(Operation *op) {
587	    auto it = opIndexMap.find(op);
588	    if (it != opIndexMap.end())
589	      return it->second;
590	
591	    // Check if the operation location has a reserved index and return it.
592	    auto reserved = getDebugReserved(op->getLoc());
593	    if (reserved != Bytecode::DebugReserved::SIZE)
594	      return static_cast<uint64_t>(reserved);
595	
596	    // Adjust the index to account for reserved indices.
597	    uint64_t opIndex = opIndexMap.size() +
598	                       static_cast<uint64_t>(Bytecode::DebugReserved::SIZE);
599	
600	    opIndexMap[op] = opIndex;
601	    return opIndex;
602	  }
603	
604	  /// This method adds a debug info attribute to an operation.
605	  void addDebugInfo(uint64_t opIndex, Attribute attr) {
606	    // Nothing to do if the operation has a reserved index.
607	    if (opIndex < static_cast<uint64_t>(Bytecode::DebugReserved::SIZE))
608	      return;
609	
610	    // Adjust the index to account for reserved indices.
611	    opIndex -= static_cast<uint64_t>(Bytecode::DebugReserved::SIZE);
612	
613	    if (opIndex >= debuginfoIndices.size())
614	      debuginfoIndices.resize(opIndex + 1);
615	    debuginfoIndices[opIndex].push_back(getDebugInfoIndex(attr));
616	  }
617	
618	  // debuginfo-section =:
619	  //   diOpsNum[varint]          // Total number of operations with debug info
620	  //   padding[bytes]            // Align to 4 bytes
621	  //   diIndexOffsets[uint32_t]  // Per op offset into the debug info indices
622	  //   diIndicesNum[varint]      // Total number of debug info indices
623	  //   padding[bytes]            // Align to 8 bytes
624	  //   diIndices[uint64_t]       // Array of debug indices to debug info
625	  //   attributes diAttrNum[varint]         // Total number of debug info
626	  //   attributes padding[bytes]            // Align to 4 bytes
627	  //   diOffsets[uint32_t]       // Per debug info attribute offset into the
628	  //   debug info data diData[bytes]             // Data for each debug info
629	  //   attribute
630	  //
631	  // diData =:
632	  //   DebugTag[byte]            // Indicates the debug info attribute type
633	  //   debuginfo-encoding        // Format depends on DebugTag
634	  LogicalResult writeDebugInfoSection(raw_ostream &stream) {
635	    // Skip writing the section if there are no debug info attributes.
636	    if (debuginfoIndices.empty() && debuginfoList.empty())
637	      return success();
638	
639	    SmallVector<char> diData;
640	    llvm::raw_svector_ostream diStream(diData);
641	    EncodingWriter diWriter(diStream);
642	
643	    // Write the total number of operations with debug info.
644	    diWriter.writeVarInt(debuginfoIndices.size());
645	
646	    // Align to 4 bytes for the uint32_t diIndexOffsetsPtr.
647	    auto alignment = alignof(uint32_t);
648	    diWriter.alignTo(alignment);
649	
650	    // Write the per op offset into the debug info indices.
651	    uint32_t offset = 0;
652	    for (auto &diIndices : debuginfoIndices) {
653	      diWriter.writeLE<uint32_t>(offset);
654	      offset += diIndices.size();
655	    }
656	
657	    // Write the total number of debug info indices.
658	    diWriter.writeVarInt(offset);
659	
660	    // Align to 8 bytes for the uint64_t diIndicesPtr.
661	    diWriter.alignTo(alignof(uint64_t));
662	
663	    // Write the array of debug indices to debug info attributes.
664	    for (const auto &indices : debuginfoIndices)
665	      for (uint64_t diIndex : indices)
666	        diWriter.writeLE<uint64_t>(diIndex);
667	
668	    // Write the total number of debug info attributes.
669	    diWriter.writeVarInt(debuginfoList.size());
670	
671	    // Align to 4 bytes for the uint32_t diOffsetsPtr.
672	    diWriter.alignTo(alignment);
673	
674	    // Save the current position to fix up offsets later.
675	    auto offsetsPtr = diWriter.tell();
676	
677	    // Reserve space for the offset table (filled later).
678	    for (size_t i = 0; i < debuginfoList.size(); ++i)
679	      diWriter.writeLE<uint32_t>(0);
680	
681	    // Write each debug info attribute and record its starting offset.
682	    SmallVector<uint32_t> finalOffsets;
683	    finalOffsets.reserve(debuginfoList.size());
684	
685	    uint32_t running = 0;
686	    for (auto attr : debuginfoList) {
687	      finalOffsets.push_back(running);
688	      auto before = diWriter.tell();
689	      if (failed(serializeDebugInfo(attr, diWriter)))
690	        return emitError(UnknownLoc::get(attr.getContext()),
691	                         "failed to serialize debug info attribute");
692	      running += static_cast<uint32_t>(diWriter.tell() - before);
693	    }
694	
695	    // Copy the pre-computed offsets into the reserved slot.
696	    std::copy_n(finalOffsets.begin(), finalOffsets.size(),
697	                reinterpret_cast<uint32_t *>(diData.data() + offsetsPtr));
698	
699	    // Write the debug info section header.
700	    writeSectionHeader(stream, Bytecode::Section::Debug, diData.size(),
701	                       diWriter.getRequiredAlignment());
702	
703	    // Write the debug info section data directly.
704	    stream.write(diData.data(), diData.size());
705	
706	    return success();
707	  }
708	
709	  LogicalResult validateDebugInfo(Operation *op) {
710	    return validateDebugInfo(op, op->getLoc());
711	  }
712	
713	  LogicalResult validateDebugInfo(Operation *op, Attribute attr) {
714	    return TypeSwitch<Attribute, LogicalResult>(attr)
715	        .Case<DILocAttr, FileLineColLoc, UnknownLoc>(
716	            [&](Attribute attr) { return success(); })
717	        .Case([&](CallSiteLoc attr) {
718	          if (failed(validateDebugInfo(op, attr.getCaller())) ||
719	              failed(validateDebugInfo(op, attr.getCallee())))
720	            return failure();
721	          return success();
722	        })
723	        .Default([&](Attribute attr) { return invalidLocError(op, attr); });
724	  }
