726	private:
727	  /// This method gets or creates an index for a debug info attribute.
728	  uint64_t getDebugInfoIndex(Attribute attr) {
729	    const void *key = attr.getAsOpaquePointer();
730	    auto it = diIndexMap.find(key);
731	    if (it != diIndexMap.end())
732	      return it->second;
733	
734	    // Check if the debug info attribute has a reserved index and return it.
735	    auto reserved = getDebugReserved(attr);
736	    if (reserved != Bytecode::DebugReserved::SIZE)
737	      return static_cast<uint64_t>(reserved);
738	
739	    // Register any dependent debug info attributes.
740	    registerDebugInfo(attr);
741	
742	    // Adjust the index to account for reserved indices.
743	    uint64_t diIndex = debuginfoList.size() +
744	                       static_cast<uint64_t>(Bytecode::DebugReserved::SIZE);
745	
746	    diIndexMap[key] = diIndex;
747	    debuginfoList.push_back(attr);
748	    return diIndex;
749	  }
750	
751	  LogicalResult invalidLocError(Operation *op, Attribute attr) {
752	    return op->emitError()
753	           << "unsupported location, got "
754	           << TypeSwitch<Attribute, StringRef>(attr)
755	                  .Case([&](OpaqueLoc loc) { return "OpaqueLoc"; })
756	                  .Case([&](NameLoc loc) { return "NameLoc"; })
757	                  .Case([&](FusedLoc loc) { return "FusedLoc"; })
758	                  .Case([&](UnknownLoc loc) { return "UnknownLoc"; })
759	                  .Case([&](FileLineColLoc loc) { return "FileLineColLoc"; })
760	                  .Default([&](Attribute loc) { return "Unknown Attribute"; })
761	           << ", expected DILocAttr or CallSiteLoc";
762	  }
763	
764	  Bytecode::DebugReserved getDebugReserved(Attribute attr) {
765	    return TypeSwitch<Attribute, Bytecode::DebugReserved>(attr)
766	        .Case<FileLineColLoc, UnknownLoc>(
767	            [](auto loc) { return Bytecode::DebugReserved::UnknownLoc; })
768	        .Default([](Attribute) { return Bytecode::DebugReserved::SIZE; });
769	  }
770	
771	  void registerDebugInfo(Attribute attr) {
772	    TypeSwitch<Attribute, void>(attr)
773	        .Case([&](DICompileUnitAttr diCompileUnit) {
774	          getDebugInfoIndex(diCompileUnit.getFile());
775	        })
776	        .Case([&](DILexicalBlockAttr diLexicalBlock) {
777	          getDebugInfoIndex(diLexicalBlock.getScope());
778	          getDebugInfoIndex(diLexicalBlock.getFile());
779	        })
780	        .Case([&](DILocAttr diLoc) { getDebugInfoIndex(diLoc.getScope()); })
781	        .Case([&](DISubprogramAttr diSubprogram) {
782	          getDebugInfoIndex(diSubprogram.getFile());
783	          getDebugInfoIndex(diSubprogram.getCompileUnit());
784	        })
785	        .Case([&](CallSiteLoc callSiteLoc) {
786	          getDebugInfoIndex(callSiteLoc.getCallee());
787	          getDebugInfoIndex(callSiteLoc.getCaller());
788	        })
789	        .Case([&](FusedLoc FusedLoc) {
790	          for (auto subLoc : FusedLoc.getLocations())
791	            getDebugInfoIndex(subLoc);
792	        })
793	        .Case(
794	            [&](NameLoc nameLoc) { getDebugInfoIndex(nameLoc.getChildLoc()); })
795	        .Case([&](OpaqueLoc opaqueLoc) {
796	          getDebugInfoIndex(opaqueLoc.getFallbackLocation());
797	        })
798	        .Default([](Attribute) {});
799	  }
