801	  // di-compile-unit =:
802	  //   DebugTag[DICompileUnit]
803	  //   diFileIndex[varint] - DIFileAttr
804	  LogicalResult serialize(DICompileUnitAttr diCompileUnit,
805	                          EncodingWriter &writer) {
806	    writer.writeVarInt(Bytecode::DebugTag::DICompileUnit);
807	    writer.writeVarInt(getDebugInfoIndex(diCompileUnit.getFile()));
808	    return success();
809	  }
810	  // di-file =:
811	  //   DebugTag[DIFile]
812	  //   fileNameIndex[varint] - StringAttr
813	  //   directoryIndex[varint] - StringAttr
814	  LogicalResult serialize(DIFileAttr diFile, EncodingWriter &writer) {
815	    writer.writeVarInt(Bytecode::DebugTag::DIFile);
816	    writer.writeVarInt(strMgr.getStringIndex(diFile.getName()));
817	    writer.writeVarInt(strMgr.getStringIndex(diFile.getDirectory()));
818	    return success();
819	  }
820	  // di-lexical-block =:
821	  //   DebugTag[DILexicalBlock]
822	  //   diScopeIndex[varint] - DILocalScopeAttr
823	  //   diFileIndex[varint] - DIFileAttr
824	  //   lineNumber[varint] - unsigned
825	  //   columnNumber[varint] - unsigned
826	  LogicalResult serialize(DILexicalBlockAttr diLexicalBlock,
827	                          EncodingWriter &writer) {
828	    writer.writeVarInt(Bytecode::DebugTag::DILexicalBlock);
829	    writer.writeVarInt(getDebugInfoIndex(diLexicalBlock.getScope()));
830	    writer.writeVarInt(getDebugInfoIndex(diLexicalBlock.getFile()));
831	    writer.writeVarInt(diLexicalBlock.getLine());
832	    writer.writeVarInt(diLexicalBlock.getColumn());
833	    return success();
834	  }
835	  // di-loc =:
836	  //   DebugTag[DILoc]
837	  //   diScopeIndex[varint] - DILocalScopeAttr
838	  //   fileNameIndex[varint] - StringAttr
839	  //   lineNumber[varint] - unsigned
840	  //   columnNumber[varint] - unsigned
841	  LogicalResult serialize(DILocAttr diLoc, EncodingWriter &writer) {
842	    writer.writeVarInt(Bytecode::DebugTag::DILoc);
843	    writer.writeVarInt(getDebugInfoIndex(diLoc.getScope()));
844	    writer.writeVarInt(
845	        strMgr.getStringIndex(diLoc.getSourceLoc().getFilename()));
846	    writer.writeVarInt(diLoc.getSourceLoc().getLine());
847	    writer.writeVarInt(diLoc.getSourceLoc().getColumn());
848	    return success();
849	  }
850	  // di-subprogram =:
851	  //  DebugTag[DISubprogram]
852	  //  diFileIndex[varint] - DIFileAttr
853	  //  lineNumber[varint] - unsigned
854	  //  nameIndex[varint] - StringAttr
855	  //  linkageNameIndex[varint] - StringAttr
856	  //  diCompileUnitIndex[varint] - DICompileUnitAttr
857	  //  scopeLine[varint] - unsigned
858	  LogicalResult serialize(DISubprogramAttr diSubprogram,
859	                          EncodingWriter &writer) {
860	    writer.writeVarInt(Bytecode::DebugTag::DISubprogram);
861	    writer.writeVarInt(getDebugInfoIndex(diSubprogram.getFile()));
862	    writer.writeVarInt(diSubprogram.getLine());
863	    writer.writeVarInt(strMgr.getStringIndex(diSubprogram.getName()));
864	    writer.writeVarInt(strMgr.getStringIndex(diSubprogram.getLinkageName()));
865	    writer.writeVarInt(getDebugInfoIndex(diSubprogram.getCompileUnit()));
866	    writer.writeVarInt(diSubprogram.getScopeLine());
867	    return success();
868	  }
869	
870	  // call-site =:
871	  //  DebugTag[CallSite]
872	  //  diCalleeIndex[varint] - LocationAttr
873	  //  diCallerIndex[varint] - LocationAttr
874	  LogicalResult serialize(CallSiteLoc callSiteLoc, EncodingWriter &writer) {
875	    writer.writeVarInt(Bytecode::DebugTag::CallSite);
876	    writer.writeVarInt(getDebugInfoIndex(callSiteLoc.getCallee()));
877	    writer.writeVarInt(getDebugInfoIndex(callSiteLoc.getCaller()));
878	    return success();
879	  }
880	
881	  // unknown =:
882	  //   DebugTag[Unknown]
883	  LogicalResult serializeUnknown(EncodingWriter &writer) {
884	    writer.writeVarInt(Bytecode::DebugTag::Unknown);
885	    return success();
886	  }
887	
888	  LogicalResult serializeDebugInfo(Attribute attr, EncodingWriter &writer) {
889	    return TypeSwitch<Attribute, LogicalResult>(attr)
890	        // Serialize known debug info attributes.
891	        .Case<DICompileUnitAttr, DIFileAttr, DILexicalBlockAttr,
892	              DISubprogramAttr>(
893	            [&](auto attr) -> LogicalResult { return serialize(attr, writer); })
894	        // Serialize known locations types.
895	        .Case<DILocAttr, CallSiteLoc>(
896	            [&](auto loc) { return serialize(loc, writer); })
897	        .Case<UnknownLoc, FileLineColLoc>([&](auto loc) { return success(); })
898	        .Default([&](Attribute) -> LogicalResult { return failure(); });
899	  }
