950	  FunctionTableWriter(TypeManager &tm, ConstantManager &cm, StringManager &sm,
951	                      DebugInfoWriter &dm, const BytecodeWriterConfig &cfg)
952	      : typeMgr(tm), constMgr(cm), strMgr(sm), debuginfo(dm), config(cfg) {}
