1243	  // Template for other native C++ types that need conversion
1244	  template <typename T>
1245	  LogicalResult
1246	  writeOpAttribute(Operation *op, StringRef attrName, const T &nativeValue,
1247	                   EncodingWriter &writer, TypeManager &typeMgr,
1248	                   ConstantManager &constMgr, StringManager &strMgr) {
1249	    // --- Direct Inline Writes ---
1250	    if constexpr (std::is_same_v<T, bool>) {
1251	      writer.writeByte(nativeValue ? 0x01 : 0x00);
1252	      return success();
1253	    } else if constexpr (is_cuda_tile_enum<T>::value) {
1254	      // Check per-value version requirements.
1255	      if (!isEnumValueAvailableInVersion<T>(nativeValue,
1256	                                            config.bytecodeVersion))
1257	        return op->emitError()
1258	               << "enum value for attribute '" << attrName
1259	               << "' is not available in bytecode version "
1260	               << static_cast<int>(config.bytecodeVersion.getMajor()) << "."
1261	               << static_cast<int>(config.bytecodeVersion.getMinor());
1262	      writer.writeVarInt(static_cast<uint32_t>(nativeValue));
1263	      return success();
1264	    } else if constexpr (std::is_same_v<std::decay_t<T>,
1265	                                        ::llvm::ArrayRef<int32_t>> ||
1266	                         std::is_same_v<std::decay_t<T>,
1267	                                        ::llvm::ArrayRef<int64_t>> ||
1268	                         std::is_same_v<std::decay_t<T>,
1269	                                        ::llvm::ArrayRef<int>>) {
1270	      writer.writeLEVarSize(nativeValue);
1271	      return success();
1272	    } else if constexpr (std::is_integral_v<T>) {
1273	      unsigned width = sizeof(T) * CHAR_BIT;
1274	      if (width == 0 || width > 64)
1275	        return op->emitError()
1276	               << "unsupported inline integer width for attribute '" << attrName
1277	               << "': " << width;
1278	      writer.writeVarInt(nativeValue);
1279	      return success();
1280	    } else if constexpr (std::is_base_of_v<Attribute, T>) {
1281	      // If the attribute implements an interface, we need to write it
1282	      // self-contained.
1283	      bool isSelfContained = mlir::detail::IsInterface<T>::value;
1284	      return writeSingleAttribute(op, attrName, nativeValue, writer, typeMgr,
1285	                                  constMgr, strMgr, isSelfContained);
1286	    } else if constexpr (std::is_same_v<std::decay_t<T>, StringRef>) {
1287	      writer.writeVarInt(strMgr.getStringIndex(nativeValue));
1288	      return success();
1289	      // --- Unsupported ---
1290	    } else {
1291	      return op->emitError(
1292	                 "unsupported native C++ type encountered during attribute "
1293	                 "serialization for attribute '")
1294	             << attrName << "'";
1295	    }
1296	  }
