1616	//===----------------------------------------------------------------------===//
1617	// BytecodeWriter Implementation
1618	// Manages the overall bytecode writing process by orchestrating different
1619	// layers.
1620	//===----------------------------------------------------------------------===//
1621	
1622	/// Verify that the given module is self-contained and can be serialized into
1623	/// bytecode without external dependencies. This function performs two main
1624	/// checks:
1625	/// 1. Ensures the module only contains function and global operations at the
1626	///    top level (no other operation types are allowed in the module body).
1627	/// 2. Validates invariants for some operations. For example, ReduceOp currently
1628	///    requires only Pure operation in its region.
1629	static LogicalResult
1630	verifySelfContainedModuleAndOperationInvariants(cuda_tile::ModuleOp module) {
1631	  // Validate that we have a self-contained module that matches what we can
1632	  // encode within the bytecode (e.g. no-non functions/globals/etc. nested in
1633	  // the module).
1634	  for (Operation &op : module.getBody().front()) {
1635	    if (!isa<FunctionOpInterface, GlobalOp>(&op)) {
1636	      // Do not use op.emitRemark, as that would trigger recursive
1637	      // verification of the module again.
1638	      mlir::emitRemark(op.getLoc(), "invalid op: ") << op.getName();
1639	      return module.emitOpError(
1640	          "only function and global ops are allowed in the body");
1641	    }
1642	  }
1643	
1644	  // Allow only ops from the CudaTile dialect inside of the module (at any
1645	  // nesting level).
1646	  auto emitInvalidOpRemark = [&](Operation *invalidOp) {
1647	    emitRemark(invalidOp->getLoc(), "invalid op: ") << invalidOp->getName();
1648	  };
1649	
1650	  Dialect *dialect = module->getDialect();
1651	  WalkResult status = module->walk([&](Operation *op) {
1652	    if (op->getDialect() != dialect) {
1653	      emitInvalidOpRemark(op);
1654	      module.emitOpError("only ops from the '")
1655	          << dialect->getNamespace() << "' dialect are allowed";
1656	      return WalkResult::interrupt();
1657	    }
1658	    if (op->getParentOfType<cuda_tile::ReduceOp>() ||
1659	        op->getParentOfType<cuda_tile::ScanOp>()) {
1660	      if (!isPure(op)) {
1661	        emitInvalidOpRemark(op);
1662	        op->getParentOp()->emitOpError("only pure operations allowed");
1663	        return WalkResult::interrupt();
1664	      }
1665	    }
1666	    return WalkResult::advance();
1667	  });
1668	  if (status.wasInterrupted())
1669	    return failure();
1670	  return success();
1671	}
