std::optional<BytecodeVersion> BytecodeVersion::fromVersion(uint8_t verMajor,
                                                            uint8_t verMinor,
                                                            uint16_t verTag) {
  // Include auto-generated version validation from TableGen.
#define GEN_VERSION_VALIDATION
#include "StaticOpcodes.inc"
